 24	type InlineFilterSelectProps = {
 25	  className?: string;
 26	  menuFooter?: ReactNode;
 27	  optionLabelText?: string;
 28	  options: EnhancedSelectOptionProps[];
 29	  popperProps?: SelectPopperProps;
 30	  selected: string;
 31	  selectProps?: Omit<SelectProps, 'toggle'>;
 32	  setSelected: (val: string) => void;
 33	  toggleProps?: MenuToggleProps;
 34	};
 35	
 36	const InlineFilterSelect: FC<InlineFilterSelectProps> = ({
 37	  className,
 38	  menuFooter,
 39	  options = [],
 40	  popperProps,
 41	  selected,
 42	  selectProps,
 43	  setSelected,
 44	  toggleProps,
 45	}) => {
 46	  const [isOpen, setIsOpen] = useState<boolean>(false);
 47	  const [filterValue, setFilterValue] = useState<string>('');
 48	  const [focusedItemIndex, setFocusedItemIndex] = useState<null | number>(null);
 49	
 50	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
 51	
 52	  const onSelect = (_event: React.MouseEvent<Element, MouseEvent> | undefined, value: string) => {
 53	    if (value && value !== NO_RESULTS) {
 54	      setFilterValue('');
 55	    }
 56	    setIsOpen(false);
 57	    setFocusedItemIndex(null);
 58	    setSelected(value);
 59	  };
 60	
 61	  const selectedComponent = useMemo(() => {
 62	    if (isEmpty(selected)) return toggleProps?.placeholder;
 63	
 64	    const selectOption = options?.find((opt) => opt?.value === selected);
 65	    return <InlineFilterSelectOptionContent option={selectOption} />;
 66	  }, [selected, toggleProps?.placeholder, options]);
 67	
 68	  const filterOptions = useMemo(
 69	    () =>
 70	      options.filter((option) => option.value.toLowerCase().includes(filterValue.toLowerCase())),
 71	    [options, filterValue],
 72	  );
 73	
 74	  const groupedOptions = useMemo(
 75	    () => getGroupedOptions(filterOptions, options),
 76	    [filterOptions, options],
 77	  );
 78	
 79	  const toggle = SelectToggle({
 80	    isExpanded: isOpen,
 81	    onClick: onToggle,
 82	    selected: selectedComponent,
 83	    ...toggleProps,
 84	  });
 85	
 86	  return (
 87	    <Select
 88	      className={className}
 89	      id="select-inline-filter"
 90	      isOpen={isOpen}
 91	      isScrollable
 92	      onOpenChange={(open: boolean) => setIsOpen(open)}
 93	      onSelect={onSelect}
 94	      popperProps={popperProps}
 95	      selected={selected}
 96	      toggle={toggle}
 97	      {...selectProps}
 98	    >
 99	      <MenuSearch>
100	        <MenuSearchInput>
101	          <SearchInput
102	            onChange={(_, newFilterValue) => {
103	              if (filterValue !== newFilterValue) {
104	                setFilterValue(newFilterValue);
105	              }
106	
107	              setFocusedItemIndex(null);
108	            }}
109	            onClear={(e: SyntheticEvent<HTMLButtonElement>) => {
110	              e.stopPropagation();
111	              setFilterValue('');
112	            }}
113	            placeholder={toggleProps?.placeholder}
114	            value={filterValue}
115	          />
116	        </MenuSearchInput>
117	      </MenuSearch>
118	      <Divider />
119	      <SelectList id="select-inline-filter-listbox">
120	        <InlineFilterSelectOptions
121	          filterOptions={filterOptions}
122	          filterValue={filterValue}
123	          focusedItemIndex={focusedItemIndex}
124	          groupedOptions={groupedOptions}
125	        />
126	      </SelectList>
127	      {menuFooter && menuFooter}
128	    </Select>
129	  );
130	};
131	
132	export default InlineFilterSelect;

